import React, { useState } from "react";
import ExportInventoryButton from "./ExportInventoryButton";
import InventoryStatus from "./InventoryStatus";
import ProductDetailsView from "./ProductDetailsView";
import "./InventoryPage.css";

interface InventoryItem {
    id: number;
    name: string;
    type: string;
    category: string;
    quantity: number;
    unit: "piece" | "kg" | "litre";
    price: number;
    description?: string;
}

const sampleInventory: InventoryItem[] = [
    { id: 1, name: "Laptop", type: "Electronics", category: "Hardware", quantity: 3, unit: "piece", price: 1200, description: "High-performance laptop" },
    { id: 2, name: "Headphones", type: "Accessories", category: "Audio", quantity: 15, unit: "piece", price: 200, description: "Noise-canceling headphones" },
    { id: 3, name: "Milk", type: "Beverage", category: "Food", quantity: 20, unit: "litre", price: 1.5, description: "Organic milk" },
];

export default function InventoryPage() {
    const [inventory, setInventory] = useState<InventoryItem[]>(sampleInventory);
    const [selectedProduct, setSelectedProduct] = useState<InventoryItem | null>(null);
    const [newProduct, setNewProduct] = useState<Omit<InventoryItem, "id" | "description"> & { description?: string }>({
        name: "",
        type: "",
        category: "",
        quantity: 0,
        unit: "piece",
        price: 0,
    });

    const handleInputChange = (
        e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>
    ) => {
        const { name, value } = e.target;
        setNewProduct((prev) => ({
            ...prev,
            [name]: name === "quantity" || name === "price" ? Number(value) : value,
        }));
    };

    const handleCreateProduct = (e: React.FormEvent) => {
        e.preventDefault();
        const id = inventory.length > 0 ? Math.max(...inventory.map((i) => i.id)) + 1 : 1;
        const product: InventoryItem = {
            id,
            name: newProduct.name,
            type: newProduct.type,
            category: newProduct.category,
            quantity: newProduct.quantity,
            unit: newProduct.unit,
            price: newProduct.price,
            description: `${newProduct.quantity} ${newProduct.unit}`,
        };
        setInventory((prev) => [...prev, product]);
        setNewProduct({ name: "", type: "", category: "", quantity: 0, unit: "piece", price: 0 });
    };

    const handleSelectProduct = (productId: number) => {
        const prod = inventory.find((item) => item.id === productId) || null;
        setSelectedProduct(prod);
    };

    const handleCloseDetails = () => {
        setSelectedProduct(null);
    };

    return (
        <div className="inventory-page-container">
            <h2>Inventory Management</h2>

            {/* Yeni Ürün Oluşturma Formu */}
            <form className="create-product-form" onSubmit={handleCreateProduct}>
                <input
                    name="name"
                    type="text"
                    placeholder="Ürün Adı"
                    value={newProduct.name}
                    onChange={handleInputChange}
                    required
                />
                <input
                    name="type"
                    type="text"
                    placeholder="Ürün Cinsi"
                    value={newProduct.type}
                    onChange={handleInputChange}
                    required
                />
                <input
                    name="category"
                    type="text"
                    placeholder="Ürün Tipi"
                    value={newProduct.category}
                    onChange={handleInputChange}
                    required
                />
                <input
                    name="quantity"
                    type="number"
                    placeholder="Adet / Miktar"
                    value={newProduct.quantity}
                    onChange={handleInputChange}
                    required
                />
                <select
                    name="unit"
                    value={newProduct.unit}
                    onChange={handleInputChange}
                >
                    <option value="piece">Adet</option>
                    <option value="kg">Kilogram</option>
                    <option value="litre">Litre</option>
                </select>
                <input
                    name="price"
                    type="number"
                    placeholder="Fiyat"
                    value={newProduct.price}
                    onChange={handleInputChange}
                    required
                />
                <button type="submit" className="create-product-btn">
                    Oluştur
                </button>
            </form>

            {/* Stok Durumu ve Detay Görüntüleme */}
            <InventoryStatus items={inventory} onSelectItem={handleSelectProduct} />
            {selectedProduct && (
                <ProductDetailsView
                    product={selectedProduct}
                    onClose={handleCloseDetails}
                />
            )}

            {/* CSV/PDF Aktarımı */}
            <ExportInventoryButton items={inventory} />
        </div>
    );
}
